import { Newspaper, LayoutDashboard, Share2 } from 'lucide-react';

const Benefits = () => {
    const steps = [
        {
            number: '01',
            title: 'لوحة تحكم متكاملة لإدارة الأكاديمية',
            desc: 'متابعة يومية لكل تفاصيل أكاديميتك بسهولة',
            icon: <LayoutDashboard size={24} />
        },
        {
            number: '02',
            title: 'تقارير وإيصالات فورية',
            desc: 'إصدار وتنظيم الفواتير من أي مكان وفي أي وقت',
            icon: <Newspaper size={24} />
        },
        {
            number: '03',
            title: 'إدارة الاشتراكات والمدفوعات',
            desc: 'تحكم عملي في الفواتير ومتابعة الاشتراكات',
            icon: <Share2 size={24} />
        },
    ];

    return (
        <section className="bg-[#f8faff] py-24 overflow-hidden">
            <div className="container mx-auto px-4 flex flex-col lg:flex-row-reverse items-center gap-16">
                <div className="flex-1 space-y-8">
                    {steps.map((step, index) => (
                        <div key={index} className="flex items-start gap-6 group hover:translate-x-[-10px] transition-all duration-300">
                            <div className="text-4xl font-black text-[#cbd5e1] group-hover:text-[#2563eb] transition-colors">
                                {step.number}
                            </div>
                            <div className="flex-1 text-right">
                                <div className="flex items-center justify-end gap-4 mb-2">
                                    <h3 className="text-xl font-extrabold text-[#1f2937]">{step.title}</h3>
                                    <div className="w-12 h-12 rounded-2xl bg-white shadow-md flex items-center justify-center text-[#2563eb]">
                                        {step.icon}
                                    </div>
                                </div>
                                <p className="text-[#6b7280] font-semibold">{step.desc}</p>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="flex-1 w-full">
                    <div className="relative group">
                        <div className="absolute -inset-4 bg-gradient-to-r from-[#2563eb] to-[#fbbf24] rounded-[40px] opacity-10 blur-xl group-hover:opacity-20 transition-opacity"></div>
                        <div className="relative w-full aspect-video rounded-[40px] bg-white shadow-2xl overflow-hidden border-8 border-white">
                            {/* Showcase Image Placeholder */}
                            <div className="w-full h-full bg-slate-50 flex items-center justify-center">
                                <div className="text-slate-300 font-bold text-2xl">واجهة لوحة التحكم</div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default Benefits;
