import { CircleCheck } from 'lucide-react';

const Problem = () => {
    const features = [
        'ادارة تسجيل المدربين',
        'متابعة المدفوعات',
        'الوصول لطلاب جدد',
        'ادارة تسجيل الطلاب',
        'تنظيم الكورسات',
    ];

    return (
        <section className="bg-white py-24">
            <div className="container mx-auto px-4 flex flex-col md:flex-row items-center gap-20">
                <div className="flex-1">
                    <div className="w-full h-[400px] rounded-3xl bg-[#f0f0f0] flex items-center justify-center border-4 border-dashed border-gray-300">
                        {/* Placeholder image area */}
                        <div className="text-gray-400">صورة توضيحية</div>
                    </div>
                </div>

                <div className="flex-1 text-right">
                    <h2 className="text-4xl font-extrabold text-[#2563eb] mb-10 leading-tight">
                        هل تواجه صعوبة في ادارة اكاديميتك ؟
                    </h2>
                    <ul className="flex flex-col gap-5">
                        {features.map((feature, index) => (
                            <li key={index} className="flex items-center justify-end gap-4 text-xl font-bold text-[#4a4a4a]">
                                <span>{feature}</span>
                                <CircleCheck className="text-[#fbbf24] fill-[#fbbf24] text-white" size={28} />
                            </li>
                        ))}
                    </ul>
                </div>
            </div>

            <div className="mt-20 text-center px-4">
                <p className="text-2xl font-black text-[#2563eb] leading-relaxed">
                    منصتنا بتوفر لك كل الأدوات اللي تحتاجها <br /> لإدارة أكاديميتك باحتراف في مكان واحد.
                </p>
            </div>
        </section>
    );
};

export default Problem;
